import { Component, OnInit, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ApiService } from '../../core/api.service';
import { ServiceSetting } from '../../core/models';

/**
 * Storefront admin settings (`admin/settings`, admin). Lists provisioned backing
 * services (postgresql, minio) with a configured/unconfigured badge and a per-service
 * credential form. service_agent wires ApiService.getSettings()/updateSettings().
 */
@Component({
  selector: 'app-admin-settings',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './admin-settings.component.html',
  styleUrl: './admin-settings.component.css',
})
export class AdminSettingsComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);
  readonly savedKey = signal<string | null>(null);

  // Draft credential values keyed by service key.
  drafts: Record<string, string> = {};

  // Mock provisioned services — service_agent replaces with ApiService.getSettings().
  readonly settings = signal<ServiceSetting[]>([
    { key: 'postgresql', label: 'PostgreSQL database', configured: true, maskedValue: 'postgres://••••••@db:5432/storefront' },
    { key: 'minio', label: 'MinIO object storage', configured: false, maskedValue: null },
  ]);

  constructor(private api: ApiService) {}

  ngOnInit(): void {
    this.loading.set(true);
    this.error.set(null);
    this.api.getSettings().subscribe({
      next: (settings) => {
        this.settings.set(settings);
        this.loading.set(false);
      },
      error: () => {
        this.error.set('Could not load service settings.');
        this.loading.set(false);
      },
    });
  }

  save(setting: ServiceSetting): void {
    const value = (this.drafts[setting.key] ?? '').trim();
    if (!value) {
      this.error.set('Enter a value before saving.');
      return;
    }
    this.error.set(null);
    this.settings.update((list) =>
      list.map((s) =>
        s.key === setting.key ? { ...s, configured: true, maskedValue: this.mask(value) } : s,
      ),
    );
    this.drafts[setting.key] = '';
    this.savedKey.set(setting.key);
    this.api.updateSettings({ [setting.key]: value }).subscribe({ error: () => {} });
  }

  private mask(value: string): string {
    return value.length <= 4 ? '••••' : value.slice(0, 4) + '••••••';
  }
}
